-- 高級車ディーラー用プール（car の中から高価格帯 / super を抽出）
local function buildLuxuryVehiclesFromCarPool()
    local out = {}
    local carPool = Config.VehiclesData.car or {}
    for _, veh in ipairs(carPool) do
        local price = tonumber(veh.price) or 0
        local category = tostring(veh.category or '')
        if category == 'super' or price >= 500000 then
            out[#out + 1] = veh
        end
    end
    return out
end

Config.VehiclesData.luxury = buildLuxuryVehiclesFromCarPool()
